int upperBound(const vector<int>& nums, int x) {
    int low = 0, high = nums.size();
    while (low < high) {
        int mid = low + (high - low) / 2;
        if (nums[mid] <= x)
            low = mid + 1;
        else
            high = mid;
    }
    return low;
}

