function upperBound(nums, x) {
    let low = 0, high = nums.length;
    while (low < high) {
        let mid = Math.floor(low + (high - low) / 2);
        if (nums[mid] <= x) {
            low = mid + 1;
        } else {
            high = mid;
        }
    }
    return low;
}
